const assert = require('assert');
const AnnotationRegistry = require('../../../src/core/AnnotationRegistry');

describe('AnnotationRegistry (Unit)', () => {
  it('should register and retrieve annotation and processor', () => {
    class DummyAnnotation {}
    class DummyProcessor {}

    AnnotationRegistry.register('Dummy', DummyAnnotation, DummyProcessor);

    assert.strictEqual(AnnotationRegistry.getAnnotation('Dummy'), DummyAnnotation);
    assert.strictEqual(AnnotationRegistry.getProcessor('Dummy'), DummyProcessor);
  });
});